import mongoose, { Schema, Document } from 'mongoose';

interface Group extends Document {
  name: string;
  description: string;
  adminId: mongoose.ObjectId;
  members: mongoose.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const GroupSchema: Schema = new Schema({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: mongoose.SchemaTypes.ObjectId, required: true },
  members: { type: [mongoose.SchemaTypes.ObjectId], required: true },
  telegramChatId: { type: String, default: null },
  createdAt: { type: Date, default: Date.now }
});

export default mongoose.model<Group>('Group', GroupSchema);

import mongoose, { Schema, Document } from 'mongoose';

interface Recurrence {
  type: 'daily' | 'weekly' | 'custom';
  daysOfWeek?: number[];
  time: string;
}

interface Task extends Document {
  groupId: mongoose.ObjectId;
  title: string;
  description: string;
  assignees: mongoose.ObjectId[];
  rotationIndex: number;
  unavailableMembers?: mongoose.ObjectId[];
  recurrence: Recurrence;
  status: 'active' | 'paused';
}

const TaskSchema: Schema = new Schema({
  groupId: { type: mongoose.SchemaTypes.ObjectId, required: true },
  title: { type: String, required: true },
  description: { type: String, required: true },
  assignees: { type: [mongoose.SchemaTypes.ObjectId], required: true },
  rotationIndex: { type: Number, default: 0 },
  unavailableMembers: { type: [mongoose.SchemaTypes.ObjectId], default: [] },
  recurrence: {
    type: { type: String, required: true },
    daysOfWeek: { type: [Number], default: undefined },
    time: { type: String, required: true }
  },
  status: { type: String, enum: ['active', 'paused'], default: 'active' }
});

export default mongoose.model<Task>('Task', TaskSchema);

import mongoose, { Schema, Document } from 'mongoose';

interface User extends Document {
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const UserSchema: Schema = new Schema({
  username: { type: String, required: true, unique: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now }
});

export default mongoose.model<User>('User', UserSchema);

import mongoose, { Schema, Document } from 'mongoose';

interface NotificationLog extends Document {
  taskId: mongoose.ObjectId;
  sentAt: Date;
  status: 'success' | 'failed';
  errorDetails?: string;
  retryCount: number;
}

const NotificationLogSchema: Schema = new Schema({
  taskId: { type: mongoose.SchemaTypes.ObjectId, required: true },
  sentAt: { type: Date, required: true },
  status: { type: String, enum: ['success', 'failed'], required: true },
  errorDetails: { type: String, default: null },
  retryCount: { type: Number, default: 0 }
});

export default mongoose.model<NotificationLog>('NotificationLog', NotificationLogSchema);
